const alert    = $('Edit Fields').first()?.json?.alert ?? {};
const fields   = $('Edit Fields').first()?.json ?? {};
const enr      = $json.enrichment ?? {};
const summary  = enr.summary ?? {};

const rule_id    = String(fields.rule_id ?? alert.rule?.id ?? '');
const rule_level = Number(alert.rule?.level ?? 0);
const rule_desc  = alert.rule?.description ?? 'Security Alert';
const agent_name = fields.agent_name ?? alert.agent?.name ?? 'unknown';
const ioc_value  = fields.ioc_value ?? '';
const timestamp  = alert.timestamp ?? new Date().toISOString();

// Rule-specific mappings keyed by Wazuh rule ID
const ruleMap = {
  '60106': {
    title: `Brute Force — ${ioc_value} → ${agent_name}`,
    ioc_type_id: 76,
    ioc_label: 'Brute Force Source IP',
    classification_id: 4,
    asset_type_id: 9,
    extra_context: 'Multiple failed authentication attempts'
  },
  '91530': {
    title: `Suspicious Login — ${ioc_value} → ${agent_name}`,
    ioc_type_id: 76,
    ioc_label: 'Suspicious Login Source IP',
    classification_id: 2,
    asset_type_id: 9,
    extra_context: 'Credential stuffing or suspicious authentication'
  },
  '87105': {
    title: `Malicious File — ${ioc_value.slice(0, 16)}… on ${agent_name}`,
    ioc_type_id: 113,
    ioc_label: 'Malicious File Hash (SHA256)',
    classification_id: 6,
    asset_type_id: 9,
    extra_context: 'FIM detected a file matching known malware hash'
  },
  '86601': {
    title: `C2 Beaconing — ${ioc_value} from ${agent_name}`,
    ioc_type_id: 76,
    ioc_label: 'C2 Destination IP',
    classification_id: 5,
    asset_type_id: 9,
    extra_context: 'Suricata IDS detected C2 beaconing pattern'
  }
};

const m = ruleMap[rule_id] ?? {
  title: `Security Alert — Rule ${rule_id} — ${agent_name}`,
  ioc_type_id: fields.ioc_type_id ?? 76,
  ioc_label: 'IOC',
  classification_id: 1,
  asset_type_id: 9,
  extra_context: rule_desc
};

// Map Wazuh level to IRIS severity (1–6)
const lvlSeverity = [[15,6],[12,5],[10,4],[8,3],[7,2],[0,1]];
let severity_id = lvlSeverity.find(([min]) => rule_level >= min)?.[1] ?? 1;
if (summary.verdict === 'MALICIOUS') severity_id = Math.min(severity_id + 1, 6);

const verdict     = summary.verdict ?? 'UNKNOWN';
const confidence  = summary.confidence_pct ?? 0;
const flagged_by  = (summary.flagged_by ?? []).join(', ') || 'none';
const mitre_ids   = (alert.rule?.mitre?.id ?? []).join(', ');
const mitre_techs = (alert.rule?.mitre?.technique ?? []).join(', ');

const description =
  `## Automated Alert — Wazuh Rule ${rule_id}\n\n` +
  `**Agent:** ${agent_name}  \n` +
  `**Rule:** ${rule_desc} (Level ${rule_level})  \n` +
  `**IOC:** \`${ioc_value}\`  \n` +
  `**Timestamp:** ${timestamp}\n\n` +
  (mitre_ids ? `**MITRE ATT&CK:** ${mitre_techs} (${mitre_ids})\n\n` : '') +
  `---\n\n## Enrichment Summary\n\n` +
  `| Field | Value |\n|---|---|\n` +
  `| Verdict | **${verdict}** |\n` +
  `| Confidence | ${confidence}% |\n` +
  `| Flagged By | ${flagged_by} |\n\n` +
  (m.extra_context ? `**Context:** ${m.extra_context}` : '');

return [{
  json: {
    // IRIS alert fields
    alert_title: m.title,
    alert_description: description,
    alert_severity_id: severity_id,
    alert_status_id: 2,
    alert_source: 'Wazuh',
    alert_source_ref: alert.id ?? `WZ-${rule_id}-${Date.now()}`,
    alert_source_link: '',
    alert_source_event_time: timestamp,
    alert_note: '',
    alert_tags: `rule-${rule_id},wazuh,automated`,
    alert_customer_id: 1,
    alert_classification_id: m.classification_id,
    alert_iocs: [{
      ioc_value: ioc_value,
      ioc_type_id: m.ioc_type_id,
      ioc_tlp_id: 2,
      ioc_description: `${m.ioc_label} — Verdict: ${verdict} (${confidence}%)`,
      ioc_tags: `${verdict.toLowerCase()},rule-${rule_id}`
    }],
    alert_assets: [{
      asset_name: agent_name,
      asset_type_id: m.asset_type_id,
      asset_ip: alert.agent?.ip ?? '',
      asset_description: `Wazuh agent ID ${alert.agent?.id ?? 'unknown'}`
    }],
    // Pass-through for downstream nodes (prefixed to avoid IRIS field conflicts)
    _ioc_value: ioc_value,
    _ioc_type_id: m.ioc_type_id,
    _verdict: verdict,
    _user_upn: fields.user_upn ?? '',
    _agent_id: fields.agent_id ?? '',
    _agent_name: agent_name
  }
}];
